{
  "parameters": "z.object({ itemName: z.string().default("bread").describe("The name of the item to drop, e.g., 'bread'"), quantity: z.number().int().min(1).max(64).default(2).describe("The amount of the item to drop"), targetPlayerName: z.string().describe("The name of the player who should receive the items") })",
  "executionArgs": {
    "itemName": "bread",
    "quantity": 2,
    "targetPlayerName": "Bot2"
  },
  "code": "const normalize = function (n) {
  return String(n).toLowerCase().replace('minecraft:', '').replace(/_/g, ' ');
};
if (!bot.entity || bot.health <= 0) {
  return '<UNSAFE>: Bot is dead or dying.';
}
const targetName = args.targetPlayerName;
const targetPlayer = bot.players[targetName];
const targetEntity = targetPlayer ? targetPlayer.entity : Object.values(bot.entities).find(function (e) {
  return e.type === 'player' && e.username === targetName;
});
if (!targetEntity) {
  return '<NO TARGET>: Player ' + targetName + ' is not within view.';
}
const requestedItem = bot.inventory.items().find(function (i) {
  return normalize(i.name) === normalize(args.itemName) || normalize(i.displayName) === normalize(args.itemName);
});
if (!requestedItem) {
  return '<NO ITEM>: Bot does not have ' + args.itemName + ' in inventory.';
}
startBackgroundSkill(bot, 'drop_bread', async function (token) {
  const pollMs = 100;
  try {
    if (!await waitUntilWorldActive(bot, token, pollMs)) { return; }
    const movements = new Movements(bot);
    movements.canDig = false;
    bot.pathfinder.setMovements(movements);
    bot.pathfinder.setGoal(new goals.GoalFollow(targetEntity, 3));
    while (canContinueBotAction(bot, token)) {
      const currentTarget = bot.players[targetName]?.entity || bot.entities[targetEntity.id];
      if (!currentTarget || !currentTarget.isValid) { break; }
      const dist = bot.entity.position.distanceTo(currentTarget.position);
      if (dist <= 3.5) {
        bot.pathfinder.stop();
        if (!await waitUntilWorldActive(bot, token, pollMs)) { return; }
        await bot.lookAt(currentTarget.position.offset(0, 1.2, 0), true);
        if (!await waitUntilWorldActive(bot, token, pollMs)) { return; }
        const finalItemCheck = bot.inventory.items().find(function (i) {
          return normalize(i.name) === normalize(args.itemName) || normalize(i.displayName) === normalize(args.itemName);
        });
        if (finalItemCheck) {
          const dropCount = Math.min(finalItemCheck.count, args.quantity);
          await new Promise(function (resolve) {
            bot.toss(finalItemCheck.type, null, dropCount, resolve);
          });
        }
        break;
      }
      if (!await waitForActiveMs(bot, token, 500, pollMs)) { return; }
    }
  } finally {
    bot.pathfinder.setGoal(null);
    bot.clearControlStates();
  }
});
return '<STARTED>: Moving to drop ' + args.quantity + ' ' + args.itemName + ' for ' + targetName + '.';"
}
